INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('elementary-f29af906-moex-00108', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依農業用地興建農舍辦法之規定，申請興建農舍之申請人應為農民，其資格應符合之條件，下列敘述何者 錯誤？', '["申請興建農舍之該筆農業用地面積不得小於0.25公頃", "申請人之戶籍所在地及其農業用地，須在同一直轄市、縣（市）內，且其土地取得及戶籍登記均應滿3年者", "申請人無自用農舍者。申請人已領有個別農舍或集村農舍建造執照者，視為已有自用農舍", "申請人為該農業用地之所有權人，且該農業用地應確供農業使用及屬未經申請興建農舍者"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00109', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市更新條例之規定，直轄市、縣（市）主管機關得優先劃定或變更為更新地區並訂定或變更都市更新 計畫，下列情形何者不屬之？', '["建築物窳陋且非防火構造或鄰棟間隔不足，有妨害公共安全之虞", "建築物未符合都市應有之機能", "居住環境惡劣，足以妨害公共衛生或社會治安", "因戰爭、地震、火災、水災、風災或其他重大事變遭受損壞"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00110', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市計畫法之規定，都市計畫應擬定「主要計畫書」及「細部計畫書」，下列敘述何者正確？', '["主要計畫書，除用文字、圖表說明外，應附主要計畫圖，其比例尺不得小於一萬五千分之一", "主要計畫之實施進度以10年為一期，最長不得超過25年", "細部計畫書之細部計畫圖比例尺不得小於一千二百分之一", "細部計畫核定發布實施後，應於2年內豎立都市計畫樁、計算坐標及辦理地籍分割測量"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00111', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依國土計畫法之規定，擬定機關應依法劃設各國土功能分區，下列何者不屬之？', '["國土保育地區", "城鄉發展地區", "農業發展地區", "國家公園地區"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00112', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市計畫法之規定，有關都市計畫之變更，下列敘述何者錯誤？', '["都市計畫經發布實施後，不得隨時任意變更。但擬定計畫之機關每5年內至少應通盤檢討一次", "通盤檢討須依據發展情況，並參考人民建議作必要之變更。對於非必要之公共設施用地，應變更其使用", "都市計畫經發布實施後，為適應國防或經濟發展之需要時，當地直轄市、縣（市）政府或鄉、鎮、縣轄 市公所，應視實際情況迅行變更", "都市計畫之迅行變更，內政部或縣（市）政府得指定各該原擬定之機關限期為之，必要時，並得逕為變更"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00113', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依都市危險及老舊建築物加速重建條例之規定，於本條例施行後一定期間內申請之重建計畫，得依規定再 給予獎勵，下列敘述何者錯誤？', '["施行後3年內：各該建築基地基準容積百分之十", "施行後第4年：各該建築基地基準容積百分之八", "施行後第5年：各該建築基地基準容積百分之六", "施行後第6年：各該建築基地基準容積百分之二"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00114', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法及相關解釋之規定，有關土地登記之更正，下列敘述何者錯誤？', '["須因登記錯誤或遺漏", "須不妨害原登記之同一性", "須以書面向中央地政機關申請核准", "須由登記人員或利害關係人申請"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00115', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依地籍測量實施規則之規定，有關地籍圖重測之敘述，下列何者錯誤？', '["已辦地籍測量之地區，因地籍原圖破損、滅失、比例尺變更或其他重大原因，得重新實施地籍測量", "地籍圖重測，應以段為實施單位", "直轄市、縣（市）重測地區由中央主管機關會同直轄市、縣（市）主管機關勘定", "重測地區勘定後，中央主管地政機關應將重測地區之範圍繪具圖說，連同應行注意事項，在土地所在地 之鄉（鎮、市、區）公所及適當處所公布"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00116', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地法之規定，有關繼承登記之敘述，下列何者錯誤？', '["繼承登記者，得自繼承開始之日起，6個月內為之", "聲請逾期者，每逾1個月得處應納登記費額1倍之罰鍰", "自繼承開始之日起逾 1 年未辦理繼承登記者，經該管直轄市或縣市地政機關查明後，應即公告繼承人 於5個月內聲請登記", "經公告於期限內仍未聲請者，得由地政機關予以列冊管理，其期間為15年"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00117', 'elementary-f29af906', 'elementary-f29af906-moex-114-5850e941', 'sub-elementary-f29af906-03', NULL, 'single_choice', '依土地登記規則之規定，於一定要件下，登記機關應以書面敘明理由及法令依據，駁回登記之申請，下列 敘述何者不屬其要件？', '["不屬受理登記機關管轄", "依法不應登記", "申請人之資格不符或其代理人之代理權有欠缺", "逾期未補正或未照補正事項完全補正"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:50+00:00", "source_pdf_sha1": "3aabf909ef04", "answer_pdf_sha1": "d1249a2da008", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "516", "s": "0403", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地法大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
